from __future__ import annotations

import argparse
import json
import os
import shlex
import shutil
import subprocess
import sys
from pathlib import Path
from typing import Dict, List, Tuple

import yaml

PROJECT_ROOT = Path(__file__).resolve().parents[2]
RODYN_ROOT = PROJECT_ROOT / 'third_party' / 'rodyn-slam'
GMA_ROOT = PROJECT_ROOT / 'third_party' / 'gma-upstream'


TUM_CONFIG_MAP = {
    'rgbd_dataset_freiburg1_xyz': 'configs/Tum/fr1_xyz.yaml',
    'rgbd_dataset_freiburg3_walking_xyz': 'configs/Tum/fr3_walk_xyz.yaml',
    'rgbd_dataset_freiburg3_walking_static': 'configs/Tum/fr3_walk_static.yaml',
    'rgbd_dataset_freiburg3_walking_halfsphere': 'configs/Tum/fr3_walk_half.yaml',
}

BONN_CONFIG_MAP = {
    'rgbd_bonn_balloon': 'configs/BONN/bonn_balloon.yaml',
    'rgbd_bonn_balloon2': 'configs/BONN/bonn_balloon2.yaml',
}


def _read_list(path: Path) -> List[str]:
    lines: List[str] = []
    with path.open('r', encoding='utf-8') as f:
        for raw in f:
            line = raw.strip()
            if not line or line.startswith('#'):
                continue
            lines.append(line)
    return lines


def _write_list(path: Path, lines: List[str]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open('w', encoding='utf-8') as f:
        f.write('# autogenerated Rodyn subset\n')
        for line in lines:
            f.write(line + '\n')


def _ensure_subset(sequence_dir: Path, subset_dir: Path, frames: int, stride: int) -> Dict[str, object]:
    subset_dir.mkdir(parents=True, exist_ok=True)
    for dirname in ('rgb', 'depth'):
        src = sequence_dir / dirname
        dst = subset_dir / dirname
        if dst.exists() or dst.is_symlink():
            if dst.is_symlink() or dst.is_file():
                dst.unlink()
            else:
                shutil.rmtree(dst)
        dst.symlink_to(src)

    for aux_name in ('groundtruth.txt', 'pose.txt'):
        src = sequence_dir / aux_name
        if src.exists():
            dst = subset_dir / aux_name
            if dst.exists() or dst.is_symlink():
                dst.unlink()
            dst.symlink_to(src)

    rgb_lines = _read_list(sequence_dir / 'rgb.txt')
    depth_lines = _read_list(sequence_dir / 'depth.txt')
    rgb_sel = rgb_lines[:: max(1, int(stride))]
    depth_sel = depth_lines[:: max(1, int(stride))]
    if int(frames) > 0:
        rgb_sel = rgb_sel[: int(frames)]
        depth_sel = depth_sel[: int(frames)]
    _write_list(subset_dir / 'rgb.txt', rgb_sel)
    _write_list(subset_dir / 'depth.txt', depth_sel)
    return {
        'frames_requested': int(frames),
        'stride': int(stride),
        'rgb_entries': int(len(rgb_sel)),
        'depth_entries': int(len(depth_sel)),
    }


def _load_yaml(path: Path) -> dict:
    with path.open('r', encoding='utf-8') as f:
        return yaml.safe_load(f)


def _save_yaml(path: Path, data: dict) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open('w', encoding='utf-8') as f:
        yaml.safe_dump(data, f, sort_keys=False)


def _official_config_rel(sequence: str, dataset_kind: str) -> str | None:
    if dataset_kind == 'bonn':
        return BONN_CONFIG_MAP.get(sequence)
    return TUM_CONFIG_MAP.get(sequence)


def _build_local_config(sequence: str, dataset_kind: str, subset_dir: Path, out_root: Path, exp_name: str,
                        first_iters: int, iters: int, track_iters: int, edge_iters: int, mesh_res: int, mesh_voxel: float, map_every: int, keyframe_every: int,
                        checkpoint_path: Path) -> Tuple[Path, dict]:
    config_rel = _official_config_rel(sequence, dataset_kind)
    local_cfg_path = RODYN_ROOT / 'configs' / 'local_s1' / f'{sequence}.yaml'
    if config_rel is not None:
        cfg = _load_yaml(RODYN_ROOT / config_rel)
        # If original config inherits, resolve it into a merged dict by loading parent and overriding.
        inherit = cfg.get('inherit_from')
        if inherit:
            base = _load_yaml(RODYN_ROOT / inherit)
            def merge(dst: dict, src: dict) -> dict:
                for key, value in src.items():
                    if isinstance(value, dict) and isinstance(dst.get(key), dict):
                        merge(dst[key], value)
                    else:
                        dst[key] = value
                return dst
            cfg = merge(base, {k: v for k, v in cfg.items() if k != 'inherit_from'})
    else:
        if dataset_kind == 'bonn':
            cfg = _load_yaml(RODYN_ROOT / 'configs/BONN/bonn.yaml')
            cfg['mapping']['bound'] = [[-4.0, 4.0], [-0.5, 3.5], [-6.0, 2.0]]
            cfg['mapping']['marching_cubes_bound'] = [[-4.0, 4.0], [-0.5, 3.5], [-6.0, 2.0]]
            cfg.setdefault('cam', {})['crop_edge'] = int(cfg.get('cam', {}).get('crop_edge', 10) or 10)
            cfg['cam']['crop_size'] = cfg.get('cam', {}).get('crop_size', [384, 512]) or [384, 512]
            cfg['cam']['distortion'] = cfg.get('cam', {}).get('distortion', [0.039903, -0.099343, -0.000730, -0.000144, 0.0])
        else:
            cfg = _load_yaml(RODYN_ROOT / 'configs/Tum/tum.yaml')
            cfg['mapping']['bound'] = [[-6.0, 6.0], [-5.0, 6.0], [-1.0, 3.0]]
            cfg['mapping']['marching_cubes_bound'] = [[-3.5, 2.5], [-2.5, 2.5], [-0.2, 3.0]]

    cfg['data']['trainskip'] = int(cfg.get('data', {}).get('trainskip', 1) or 1)
    cfg['data']['datadir'] = str(subset_dir)
    cfg['data']['output'] = str(out_root)
    cfg['data']['exp_name'] = exp_name
    cfg['data']['num_workers'] = 0
    cfg['flow']['checkpoint'] = str(checkpoint_path)
    cfg['mapping']['first_mesh'] = False
    cfg['mapping']['first_iters'] = int(first_iters)
    cfg['mapping']['iters'] = int(iters)
    cfg['tracking']['iter'] = int(track_iters)
    cfg['tracking']['edge_iter'] = int(edge_iters)
    cfg['mapping']['map_every'] = int(map_every)
    cfg['mapping']['keyframe_every'] = int(keyframe_every)
    cfg['mesh']['resolution'] = int(mesh_res)
    cfg['mesh']['voxel_final'] = float(mesh_voxel)
    cfg['mesh']['visualisation'] = False
    cfg['img']['visualisation'] = False
    cfg['training']['seg_mask'] = False
    cfg['training']['edge_feature'] = False
    cfg['training']['motion_mask'] = False
    _save_yaml(local_cfg_path, cfg)
    return local_cfg_path, cfg


def _find_latest_mesh(exp_dir: Path) -> Path:
    meshes = sorted(exp_dir.glob('mesh_track*.ply'))
    if not meshes:
        raise FileNotFoundError(f'No RoDyn mesh found in {exp_dir}')
    return meshes[-1]


def main() -> None:
    ap = argparse.ArgumentParser(description='Run RoDyn-SLAM on a local subset and export a mesh for benchmark adapter.')
    ap.add_argument('--dataset_root', type=str, required=True)
    ap.add_argument('--sequence', type=str, required=True)
    ap.add_argument('--dataset_kind', type=str, choices=['tum', 'bonn'], required=True)
    ap.add_argument('--out_mesh', type=str, required=True)
    ap.add_argument('--out_meta', type=str, default='')
    ap.add_argument('--frames', type=int, default=10)
    ap.add_argument('--stride', type=int, default=3)
    ap.add_argument('--first_iters', type=int, default=20)
    ap.add_argument('--iters', type=int, default=3)
    ap.add_argument('--track_iters', type=int, default=8)
    ap.add_argument('--edge_iters', type=int, default=0)
    ap.add_argument('--mesh_resolution', type=int, default=128)
    ap.add_argument('--map_every', type=int, default=999999)
    ap.add_argument('--keyframe_every', type=int, default=999999)
    ap.add_argument('--mesh_voxel', type=float, default=0.08)
    ap.add_argument('--gma_checkpoint', type=str, default='')
    args = ap.parse_args()

    dataset_root = Path(args.dataset_root).resolve()
    sequence_dir = dataset_root / args.sequence
    if not sequence_dir.exists():
        raise FileNotFoundError(f'Sequence directory not found: {sequence_dir}')
    if not RODYN_ROOT.exists():
        raise FileNotFoundError(f'RoDyn-SLAM repo not found: {RODYN_ROOT}')

    checkpoint = Path(args.gma_checkpoint).resolve() if args.gma_checkpoint else None
    if checkpoint is None or not checkpoint.exists():
        preferred = GMA_ROOT / 'checkpoints' / ('gma-things.pth' if args.dataset_kind == 'bonn' else 'gma-things.pth')
        if not preferred.exists():
            preferred = GMA_ROOT / 'checkpoints' / 'gma-sintel.pth'
        checkpoint = preferred
    if not checkpoint.exists():
        raise FileNotFoundError(f'GMA checkpoint not found: {checkpoint}')

    out_mesh = Path(args.out_mesh).resolve()
    run_root = out_mesh.parent / 'rodyn_run'
    subset_dir = run_root / 'subset'
    subset_meta = _ensure_subset(sequence_dir, subset_dir, frames=int(args.frames), stride=int(args.stride))

    exp_name = 'rodyn_local'
    config_path, cfg = _build_local_config(
        sequence=args.sequence,
        dataset_kind=args.dataset_kind,
        subset_dir=subset_dir,
        out_root=run_root,
        exp_name=exp_name,
        first_iters=int(args.first_iters),
        iters=int(args.iters),
        track_iters=int(args.track_iters),
        edge_iters=int(args.edge_iters),
        mesh_res=int(args.mesh_resolution),
        mesh_voxel=float(args.mesh_voxel),
        map_every=int(args.map_every),
        keyframe_every=int(args.keyframe_every),
        checkpoint_path=checkpoint,
    )

    cmd = [
        sys.executable,
        str((PROJECT_ROOT / 'scripts' / 'external' / 'rodyn_no_dynamo_entry.py').resolve()),
        str((RODYN_ROOT / 'rodynslam.py').resolve()),
        '--config',
        str(config_path.relative_to(RODYN_ROOT)),
        '--output',
        str(run_root),
    ]
    print('[rodyn-cmd]', ' '.join(shlex.quote(part) for part in cmd))
    subprocess.run(cmd, check=True, cwd=str(RODYN_ROOT))

    exp_dir = run_root / exp_name
    mesh_path = _find_latest_mesh(exp_dir)
    out_mesh.parent.mkdir(parents=True, exist_ok=True)
    shutil.copy2(mesh_path, out_mesh)

    meta = {
        'method': 'rodyn_slam',
        'sequence': args.sequence,
        'dataset_kind': args.dataset_kind,
        'subset': subset_meta,
        'config_path': str(config_path),
        'run_root': str(run_root),
        'exp_dir': str(exp_dir),
        'source_mesh': str(mesh_path),
        'exported_mesh': str(out_mesh),
        'checkpoint': str(checkpoint),
        'first_iters': int(args.first_iters),
        'iters': int(args.iters),
        'track_iters': int(args.track_iters),
        'edge_iters': int(args.edge_iters),
        'mesh_resolution': int(args.mesh_resolution),
        'mesh_voxel': float(args.mesh_voxel),
        'map_every': int(args.map_every),
        'keyframe_every': int(args.keyframe_every),
    }
    meta_path = Path(args.out_meta).resolve() if args.out_meta else out_mesh.with_name('rodyn_slam_meta.json')
    meta_path.parent.mkdir(parents=True, exist_ok=True)
    meta_path.write_text(json.dumps(meta, indent=2), encoding='utf-8')
    print(f'[done-rodyn-slam] mesh={out_mesh} meta={meta_path}')


if __name__ == '__main__':
    main()
